const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const unit = options?.unit;

  if (unit === "quarter") {
    // many news outlets use "quأ½ I"...
    switch (number) {
      case 1:
        return "I";
      case 2:
        return "II";
      case 3:
        return "III";
      case 4:
        return "IV";
    }
  } else if (unit === "day") {
    // day of week in Vietnamese has ordinal number meaning,
    // so we should use them, else it'll sound weird
    switch (number) {
      case 1:
        return "thل»© 2"; // meaning 2nd day but it's the first day of the week :D
      case 2:
        return "thل»© 3"; // meaning 3rd day
      case 3:
        return "thل»© 4"; // meaning 4th day and so on
      case 4:
        return "thل»© 5";
      case 5:
        return "thل»© 6";
      case 6:
        return "thل»© 7";
      case 7:
        return "chل»§ nhل؛­t"; // meaning Sunday, there's no 8th day :D
    }
  } else if (unit === "week") {
    if (number === 1) {
      return "thل»© nhل؛¥t";
    } else {
      return "thل»© " + number;
    }
  } else if (unit === "dayOfYear") {
    if (number === 1) {
      return "ؤ‘ل؛§u tiأھn";
    } else {
      return "thل»© " + number;
    }
  }

  // there are no different forms of ordinal numbers in Vietnamese
  return String(number);
};

