const formatDistanceLocale = {
  lessThanXSeconds: {
    one: "mأ« pak se njأ« sekondأ«",
    other: "mأ« pak se {{count}} sekonda",
  },

  xSeconds: {
    one: "1 sekondأ«",
    other: "{{count}} sekonda",
  },

  halfAMinute: "gjysأ«m minuti",

  lessThanXMinutes: {
    one: "mأ« pak se njأ« minute",
    other: "mأ« pak se {{count}} minuta",
  },

  xMinutes: {
    one: "1 minutأ«",
    other: "{{count}} minuta",
  },

  aboutXHours: {
    one: "rreth 1 orأ«",
    other: "rreth {{count}} orأ«",
  },

  xHours: {
    one: "1 orأ«",
    other: "{{count}} orأ«",
  },

  xDays: {
    one: "1 ditأ«",
    other: "{{count}} ditأ«",
  },

  aboutXWeeks: {
    one: "rreth 1 javأ«",
    other: "rreth {{count}} javأ«",
  },

  xWeeks: {
    one: "1 javأ«",
    other: "{{count}} javأ«",
  },

  aboutXMonths: {
    one: "rreth 1 muaj",
    other: "rreth {{count}} muaj",
  },

  xMonths: {
    one: "1 muaj",
    other: "{{count}} muaj",
  },

  aboutXYears: {
    one: "rreth 1 vit",
    other: "rreth {{count}} vite",
  },

  xYears: {
    one: "1 vit",
    other: "{{count}} vite",
  },

  overXYears: {
    one: "mbi 1 vit",
    other: "mbi {{count}} vite",
  },

  almostXYears: {
    one: "pothuajse 1 vit",
    other: "pothuajse {{count}} vite",
  },
};

export const formatDistance = (token, count, options) => {
  let result;

  const tokenValue = formatDistanceLocale[token];
  if (typeof tokenValue === "string") {
    result = tokenValue;
  } else if (count === 1) {
    result = tokenValue.one;
  } else {
    result = tokenValue.other.replace("{{count}}", String(count));
  }

  if (options?.addSuffix) {
    if (options.comparison && options.comparison > 0) {
      return "nأ« " + result;
    } else {
      return result + " mأ« parأ«";
    }
  }

  return result;
};
