const formatRelativeLocale = {
  lastWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'proإ،le nedelje u' p";
      case 3:
        return "'proإ،le srede u' p";
      case 6:
        return "'proإ،le subote u' p";
      default:
        return "'proإ،li' EEEE 'u' p";
    }
  },
  yesterday: "'juؤچe u' p",
  today: "'danas u' p",
  tomorrow: "'sutra u' p",
  nextWeek: (date) => {
    switch (date.getDay()) {
      case 0:
        return "'sledeؤ‡e nedelje u' p";
      case 3:
        return "'sledeؤ‡u sredu u' p";
      case 6:
        return "'sledeؤ‡u subotu u' p";
      default:
        return "'sledeؤ‡i' EEEE 'u' p";
    }
  },
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
