const formatRelativeLocale = {
  lastWeek: (date) => {
    const weekday = date.getDay();
    const last = weekday === 0 || weekday === 6 ? "أ؛ltimo" : "أ؛ltima";
    return "'" + last + "' eeee 'أ s' p";
  },
  yesterday: "'ontem أ s' p",
  today: "'hoje أ s' p",
  tomorrow: "'amanhأ£ أ s' p",
  nextWeek: "eeee 'أ s' p",
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  const format = formatRelativeLocale[token];

  if (typeof format === "function") {
    return format(date);
  }

  return format;
};
