const formatRelativeLocale = {
  lastWeek: "'o' eeee 'pasado أ،' LT",
  yesterday: "'onte أ،' p",
  today: "'hoxe أ،' p",
  tomorrow: "'maأ±أ، أ،' p",
  nextWeek: "eeee 'أ،' p",
  other: "P",
};

const formatRelativeLocalePlural = {
  lastWeek: "'o' eeee 'pasado أ،s' p",
  yesterday: "'onte أ،s' p",
  today: "'hoxe أ،s' p",
  tomorrow: "'maأ±أ، أ،s' p",
  nextWeek: "eeee 'أ،s' p",
  other: "P",
};

export const formatRelative = (token, date, _baseDate, _options) => {
  if (date.getHours() !== 1) {
    return formatRelativeLocalePlural[token];
  }
  return formatRelativeLocale[token];
};
